import 'dart:convert';

PackageLock packageLockFromJson(String str) => PackageLock.fromJson(json.decode(str));

String packageLockToJson(PackageLock data) => json.encode(data.toJson());

class PackageLock {
    String name;
    int lockfileVersion;
    bool requires;
    Packages packages;

    PackageLock({
        required this.name,
        required this.lockfileVersion,
        required this.requires,
        required this.packages,
    });

    factory PackageLock.fromJson(Map<String, dynamic> json) => PackageLock(
        name: json["name"],
        lockfileVersion: json["lockfileVersion"],
        requires: json["requires"],
        packages: Packages.fromJson(json["packages"]),
    );

    Map<String, dynamic> toJson() => {
        "name": name,
        "lockfileVersion": lockfileVersion,
        "requires": requires,
        "packages": packages.toJson(),
    };
}

